mapper.select:
SELECT TS.SERVICE_ID, TS.WORK_CD, TN.CARID_NO, TS.CAR_NO, TS.COMPANY_ID, TC.COMPANY_NM, PKG_COMMON.FN_DECRYPT(TN.BASE_ADDRESS) AS BASE_ADDRESS, PKG_COMMON.FN_DECRYPT(TN.BASE_ADDRESS_DT) AS BASE_ADDRESS_DT, TN.BUY_AMT, TS.MEMBER_ID, TO_CHAR(TS.REQUEST_DT, 'MM.DD HH24:MI') AS REQUEST_DT, TO_CHAR(TS.PROC_DT, 'YYYYMMDD') AS PROC_DT, TS.PROC_ST, TN.NUMPLATE_GB, TN.PAY_ST, TN.PROC_CD, TN.TASK_CD, TN.BOND_DC, TN.VBANK_NO, TS.JUDGE_ST, TO_CHAR(TS.JUDGE_DT, 'YYYYMMDD') AS JUDGE_DT, TN.REQ_CAR_NO, TN.OWNER_NM, TMD.MEMBER_NM, CD.DELIVERY_GB, NL.PROC_ST AS NUM_PROC_ST, CD.CUSTOMER_NM, TN.IMSINUM_YN, TO_CHAR(TN.IMSINUM_DT, 'MM-DD HH24:MI') AS IMSINUM_DT, TN.FUEL_CD, TN.CAR_NM, TN.CAR_KD, TN.NTAX_APPLC_CD, TN.GOVT_TX, TN.LOW_POLLUTION_YN, TS.GOVT_ID, TS.RETURN_TX, PM.VBANK_NO AS TAX_VBANK_NO, TN.T_VBANK_ID, TN.TOTAL_AMT, (SELECT PAY_AMT FROM TR_PAYMENT WHERE SERVICE_ID = TN.SERVICE_ID AND PAY_KD = 'INJI') AS INJI_AMT, (SELECT PAY_AMT FROM TR_PAYMENT WHERE SERVICE_ID = TN.SERVICE_ID AND PAY_KD = 'STAMP') AS STAMP_AMT, (SELECT PAY_AMT FROM TR_PAYMENT WHERE SERVICE_ID = TN.SERVICE_ID AND PAY_KD = 'TNUM') AS TNUM_AMT, (SELECT PAY_AMT FROM TR_PAYMENT WHERE SERVICE_ID = TN.SERVICE_ID AND PAY_KD = 'ACQ') AS ACQ_AMT, (SELECT PAY_AMT FROM TR_PAYMENT WHERE SERVICE_ID = TN.SERVICE_ID AND PAY_KD = 'BOND') AS BOND_AMT, (SELECT PAY_AMT FROM TR_PAYMENT WHERE SERVICE_ID = TN.SERVICE_ID AND PAY_KD = 'BFEE') AS BFEE_AMT, (SELECT PAY_AMT FROM TR_PAYMENT WHERE SERVICE_ID = TN.SERVICE_ID AND PAY_KD = 'UREG') AS UREG_AMT, (SELECT REAL_ALOAN FROM TR_PAYMENT WHERE SERVICE_ID = TN.SERVICE_ID AND PAY_KD = 'BOND') AS REAL_BOND_AMT, PKG_COMMON.FN_DECRYPT(CD.DELIVERY_ADDR) || ' ' || PKG_COMMON.FN_DECRYPT(CD.DELIVERY_ADDR_DT) AS DELIVERY_ADDR, CD.RECEIVE_NM, PKG_COMMON.FN_DECRYPT(CD.RECEIVE_TEL_NO) AS RECEIVE_TEL_NO, (SELECT SERIAL_NO FROM ( SELECT CP.SERVICE_ID, SERIAL_NO FROM TR_CAR_PAPER CP, TM_NUMPLATE_LIST NL2 WHERE CP.SERVICE_ID = NL2.SERVICE_ID ORDER BY PRINT_DT DESC ) CPP WHERE CPP.SERVICE_ID = NL.SERVICE_ID AND ROWNUM = 1) AS SERIAL_NO FROM TR_NEWCAR TN, TR_SERVICE TS, TM_COMPANY TC, TM_MEMBER_DT TMD, TR_CARNO_DETACH CD, TM_NUMPLATE_LIST NL, TR_PAYMENT PM WHERE TN.SERVICE_ID = TS.SERVICE_ID AND TS.COMPANY_ID = TC.COMPANY_ID AND TS.MEMBER_ID = TMD.MEMBER_ID AND TS.SERVICE_ID = CD.SERVICE_ID AND TS.SERVICE_ID = NL.SERVICE_ID(+) AND TN.SERVICE_ID = PM.SERVICE_ID AND PM.PAY_KD = 'ACQ' AND TS.REQUEST_DT BETWEEN TO_DATE(#{START_DT} || '00:00:00', 'YYYYMMDDHH24:MI:SS') AND TO_DATE(#{END_DT} || '23:59:59', 'YYYYMMDDHH24:MI:SS')
AND TS.WORK_CD = #{WORK_CD}
AND TS.COMPANY_ID = #{COMPANY_ID}
AND TS.COMPANY_ID IN
#{id}
AND TS.COMPANY_ID NOT IN
#{id}
AND TS.BRANCH_ID = #{BRANCH_ID}
AND TS.SANGSA_ID = #{SANGSA_ID}
AND TS.PROC_ST = #{PROC_ST}
AND TS.PROC_ST <> 'DEL'
AND TS.JUDGE_ST IS NOT NULL
AND TS.JUDGE_ST = #{JUDGE_ST}
AND (TS.CAR_NO LIKE '%' || #{CAR_NO} || '%' OR TN.CARID_NO LIKE '%' || #{CAR_NO} || '%')
AND TN.PAY_ST = #{PAY_ST}
AND TS.GOVT_ID = #{GOVT_ID}
AND NL.PROC_ST = #{NUM_PROC_ST}
AND CD.DELIVERY_GB IN
#{gb}
AND SUBSTR(TO_CHAR(TS.REQUEST_DT, 'HH24'), 1, 2) IN
#{t}
AND (CD.CUSTOMER_NM LIKE '%' || #{CUSTOMER_NM} || '%' OR TN.OWNER_NM LIKE '%' || #{CUSTOMER_NM} || '%')
AND (TMD.MEMBER_NM LIKE '%' || #{USER_NM} || '%' OR TN.GOVT_TX LIKE '%' || #{USER_NM} || '%')
AND PM.VBANK_NO LIKE '%' || #{VBANK_NO} || '%'
AND TN.NTAX_TRGET_CD <> '00'
AND TS.READ_YN IS NULL
AND (TS.READ_YN IS NULL OR TS.READ_YN = 'Y')
ORDER BY TS.REQUEST_DT DESC
